rubric.en:
Expected code/algorithm:
getOctoPar(v) {
  n = v.size();
  nr = 0;
  for (i = 0; i < n; ++i)
    if (v[i]%2 == 0 && IsOctogonal(v[i]))
      nr = nr + 1;
  return nr;
}

